249	+import { useState } from "react";
250	+import { useAccountPnl } from "@/lib/query/hooks";
251	+import { BayesApiError } from "@/lib/api/client";
252	+import { LoadingPage, ErrorMessage } from "@/components/ui/Spinner";
253	+import type { AccountPnlMarket } from "@/lib/api/types";
254	+
255	+interface AccountPnLProps {
256	+  accountId: string;
257	+}
258	+
259	+function pnlColor(value: number): string {
260	+  if (value > 0) return "var(--color-success)";
261	+  if (value < 0) return "var(--color-danger)";
262	+  return "var(--color-text)";
263	+}
264	+
265	+function formatPnl(value: number): string {
266	+  const sign = value > 0 ? "+" : "";
267	+  return `${sign}${value.toFixed(2)}`;
268	+}
269	+
270	+export function AccountPnL({ accountId }: AccountPnLProps) {
271	+  const { data, isLoading, error } = useAccountPnl(accountId);
272	+
273	+  if (!accountId) return null;
274	+
275	+  const isNotFound = error instanceof BayesApiError
276	+    && (error.status === 404 || error.code === "no_orders_found");
277	+
278	+  if (isLoading) return <LoadingPage />;
279	+
280	+  if (isNotFound) {
281	+    return (
282	+      <div style={sectionStyle}>
283	+        <h2 style={headingStyle}>Account P&L</h2>
284	+        <div style={placeholderStyle}>No trades yet</div>
285	+      </div>
286	+    );
287	+  }
288	+
289	+  if (error) {
290	+    return (
291	+      <div style={sectionStyle}>
292	+        <h2 style={headingStyle}>Account P&L</h2>
293	+        <ErrorMessage message={error instanceof Error ? error.message : "Failed to load account P&L"} />
294	+      </div>
295	+    );
296	+  }
297	+
298	+  if (!data) return null;
299	+
300	+  const { markets, summary } = data.pnl;
301	+
302	+  return (
303	+    <div style={sectionStyle}>
304	+      <h2 style={headingStyle}>Account P&L</h2>
305	+
306	+      <div style={summaryBarStyle}>
307	+        <SummaryMetric label="Cost Basis" value={summary.totalCostBasis} />
308	+        <SummaryMetric label="Current Value" value={summary.totalCurrentValue} />
309	+        <SummaryMetric label="Unrealized" value={summary.totalUnrealizedPnl} colored />
310	+        <SummaryMetric label="Realized" value={summary.totalRealizedPnl} colored />
311	+        <SummaryMetric label="Total P&L" value={summary.totalPnl} colored />
312	+      </div>
313	+
314	+      {markets.map((market) => (
315	+        <MarketPnlRow key={market.marketId} market={market} />
316	+      ))}
317	+    </div>
318	+  );
319	+}
320	+
321	+function SummaryMetric({ label, value, colored }: { label: string; value: number; colored?: boolean }) {
322	+  return (
323	+    <div style={metricBoxStyle}>
324	+      <div style={metricLabelStyle}>{label}</div>
325	+      <div style={{
326	+        fontSize: "1.1rem",
327	+        fontWeight: 600,
328	+        fontFamily: "var(--font-mono)",
329	+        color: colored ? pnlColor(value) : "var(--color-text)",
330	+      }}>
331	+        {formatPnl(value)}
332	+      </div>
333	+    </div>
334	+  );
