+        scheduleReconnect();
+      });
+    };
+
+    connect();
+
+    return () => {
+      effectClosed = true;
+      clearReconnectTimer();
+      reconnectAttemptRef.current = 0;
+      terminalStatus = null;
+      socket?.close();
+      socket = null;
+    };
+  }, [enabled, marketId, qc]);
+}
